
"use client"

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { 
  LayoutDashboard, 
  LineChart, 
  Calendar, 
  LogOut, 
  Plus, 
  Trophy,
  Activity,
  ArrowLeft,
  PieChart,
  User,
  Newspaper,
  ShieldCheck
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { TickerTape } from '@/components/tradingview/TickerTape';
import { EconomicCalendar } from '@/components/tradingview/EconomicCalendar';
import { MarketSummary } from '@/components/tradingview/MarketSummary';
import { WhatsAppButton } from '@/components/WhatsAppButton';
import { SignalCard } from '@/components/SignalCard';
import { Paywall } from '@/components/Paywall';
import { useTradingSignals } from '@/hooks/use-trading-signals';
import { useUser, useAuth } from '@/firebase';
import { signOut } from 'firebase/auth';

export default function DashboardPage() {
  const router = useRouter();
  const auth = useAuth();
  const { user, isUserLoading } = useUser();
  const { signalCount, isPaywallOpen, setIsPaywallOpen, signals, fetchSignal, freeLimit, isVip, isSyncing } = useTradingSignals();
  const [mounted, setMounted] = useState(false);

  // STRICT ACCESS CONTROL: Redirect to login if no user
  useEffect(() => {
    setMounted(true);
    if (!isUserLoading && !user) {
      router.replace('/login');
    }
  }, [user, isUserLoading, router]);

  useEffect(() => {
    if (mounted && user && !isSyncing) {
      fetchSignal('GOLD', 'Forex');
      fetchSignal('BTC', 'Crypto');
    }
  }, [mounted, user, isSyncing, fetchSignal]);

  if (!mounted || isUserLoading || !user) {
    return (
      <div className="min-h-screen bg-[#020617] flex items-center justify-center">
        <Activity className="h-8 w-8 text-primary animate-spin" />
      </div>
    );
  }

  const instruments = [
    { symbol: 'GOLD', name: 'Gold Spot', type: 'Forex' as const },
    { symbol: 'EUR/USD', name: 'Euro / US Dollar', type: 'Forex' as const },
    { symbol: 'BTC', name: 'Bitcoin', type: 'Crypto' as const },
    { symbol: 'ETH', name: 'Ethereum', type: 'Crypto' as const },
  ];

  const handleLogout = async () => {
    await signOut(auth);
    router.replace('/');
  };

  return (
    <div className="min-h-screen bg-[#020617] text-foreground flex flex-col">
      <div className="fixed top-0 w-full z-50">
        <TickerTape />
      </div>

      <div className="flex flex-1 pt-[44px]">
        {/* Sidebar */}
        <aside className="w-64 border-r border-white/5 bg-black/40 backdrop-blur-xl hidden lg:flex flex-col sticky top-[44px] h-[calc(100vh-44px)]">
          <div className="p-6">
            <Link href="/" className="flex items-center gap-2 text-lg font-black font-headline tracking-tighter">
              <LineChart className="h-6 w-6 text-primary" />
              DEEBDATA <span className="text-primary">TRADING</span>
            </Link>
          </div>
          
          <nav className="flex-1 px-4 space-y-2">
            <Link href="/dashboard" className="flex items-center gap-3 px-3 py-2 rounded-lg bg-primary/10 text-primary font-bold">
              <LayoutDashboard className="h-5 w-5" /> Dashboard
            </Link>
            <Link href="/analysis" className="flex items-center gap-3 px-3 py-2 rounded-lg hover:bg-white/5 transition-colors">
              <PieChart className="h-5 w-5" /> Analysis
            </Link>
            <Link href="/news" className="flex items-center gap-3 px-3 py-2 rounded-lg hover:bg-white/5 transition-colors">
              <Newspaper className="h-5 w-5" /> Market News
            </Link>
            <Link href="/profile" className="flex items-center gap-3 px-3 py-2 rounded-lg hover:bg-white/5 transition-colors">
              <User className="h-5 w-5" /> My Profile
            </Link>
          </nav>

          <div className="p-4 mt-auto border-t border-white/5">
            {!isVip && (
              <div className="p-4 rounded-xl bg-gradient-to-br from-secondary/50 to-transparent border border-white/5 mb-4">
                <p className="text-[10px] font-bold text-muted-foreground uppercase mb-1">Free Tier Progress</p>
                <div className="flex justify-between items-end mb-2">
                  <span className="text-xl font-bold font-headline">{signalCount}<span className="text-sm font-normal text-muted-foreground">/{freeLimit}</span></span>
                  <span className="text-[10px] font-bold text-primary">Signals</span>
                </div>
                <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                  <div className="h-full bg-primary transition-all duration-500" style={{ width: `${Math.min((signalCount / freeLimit) * 100, 100)}%` }} />
                </div>
                <Button 
                  variant="outline" 
                  size="sm" 
                  className="w-full mt-4 text-[10px] font-black uppercase tracking-widest border-primary/30 text-primary hover:bg-primary/10"
                  onClick={() => setIsPaywallOpen(true)}
                >
                  Upgrade to VIP
                </Button>
              </div>
            )}
            
            {isVip && (
              <div className="p-4 rounded-xl bg-primary/10 border border-primary/20 mb-4 flex items-center gap-3">
                <ShieldCheck className="h-8 w-8 text-primary" />
                <div>
                  <p className="text-xs font-bold text-primary uppercase">VIP ACTIVE</p>
                  <p className="text-[10px] text-muted-foreground">Unlimited Institutional Access</p>
                </div>
              </div>
            )}
            
            <div className="text-[10px] text-center text-muted-foreground/40 italic mb-4">
              Powered by Hassan Deeb
            </div>

            <Button variant="ghost" className="w-full justify-start gap-3 hover:text-destructive hover:bg-destructive/10" onClick={handleLogout}>
              <LogOut className="h-5 w-5" /> Log Out
            </Button>
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto bg-black/20">
          <header className="h-16 border-b border-white/5 flex items-center justify-between px-8 bg-black/40 backdrop-blur-md sticky top-0 z-40">
            <div className="flex items-center gap-4">
              <h1 className="text-xl font-black font-headline uppercase tracking-tight">Market Terminal</h1>
            </div>
            <div className="flex items-center gap-4">
              <Badge variant="outline" className="bg-success/10 px-3 py-1 text-[10px] font-black uppercase tracking-widest border-success/30 text-success">
                <Activity className="h-3 w-3 mr-2 animate-pulse" /> Live Execution
              </Badge>
              {!isVip && (
                <Button size="sm" className="bg-primary text-white font-black shadow-[0_0_20px_rgba(139,92,246,0.3)] hover:scale-105 transition-all" onClick={() => setIsPaywallOpen(true)}>
                  Unlock VIP
                </Button>
              )}
            </div>
          </header>

          <div className="p-8 space-y-8">
            <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
              {/* Signals Area */}
              <div className="xl:col-span-2 space-y-6">
                <div className="flex items-center justify-between">
                  <h2 className="text-2xl font-black font-headline uppercase tracking-tighter">AI Pulse Signals</h2>
                  <div className="flex gap-2">
                    {instruments.map(inst => (
                      <Button 
                        key={inst.symbol}
                        variant="outline" 
                        size="sm" 
                        className="text-[10px] font-black h-8 border-white/5 hover:border-primary/50 bg-white/5 uppercase tracking-widest"
                        onClick={() => fetchSignal(inst.symbol, inst.type)}
                      >
                        {inst.symbol}
                      </Button>
                    ))}
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {Object.entries(signals).map(([symbol, signal]) => (
                    signal && (
                      <SignalCard 
                        key={symbol}
                        symbol={symbol}
                        type={instruments.find(i => i.symbol === symbol)?.type || 'Forex'}
                        signal={signal}
                        isLocked={!isVip && signalCount > freeLimit}
                      />
                    )
                  ))}
                  
                  {Object.keys(signals).length === 0 && (
                    <Card className="border-dashed border-white/10 bg-white/5 flex items-center justify-center p-16 text-center col-span-full rounded-3xl">
                      <div className="space-y-4">
                        <div className="h-16 w-16 rounded-2xl bg-white/5 mx-auto flex items-center justify-center border border-white/10">
                          <Plus className="h-8 w-8 text-muted-foreground/50" />
                        </div>
                        <div>
                          <p className="font-black font-headline text-muted-foreground uppercase tracking-widest">No terminal data</p>
                          <p className="text-[10px] text-muted-foreground/60 font-bold uppercase tracking-tight">Select an instrument above to initiate analysis</p>
                        </div>
                      </div>
                    </Card>
                  )}
                </div>
              </div>

              {/* Sidebar Widgets */}
              <div className="space-y-8">
                <div className="space-y-4">
                  <h3 className="text-sm font-black font-headline uppercase tracking-[0.3em] text-muted-foreground flex items-center gap-2">
                    <Calendar className="h-4 w-4 text-accent" /> Institutional Events
                  </h3>
                  <EconomicCalendar />
                </div>
                <div className="space-y-4">
                  <h3 className="text-sm font-black font-headline uppercase tracking-[0.3em] text-muted-foreground flex items-center gap-2">
                    <LineChart className="h-4 w-4 text-primary" /> Global Liquidity
                  </h3>
                  <MarketSummary />
                </div>
              </div>
            </div>
          </div>
        </main>
      </div>

      <WhatsAppButton />
      <Paywall isOpen={isPaywallOpen} onClose={() => setIsPaywallOpen(false)} />
    </div>
  );
}

