"use client"

import React, { useEffect, useRef, useMemo } from 'react';
import { TrendingUp, TrendingDown, Target, ShieldAlert, BarChart3, Info, Lock, Users } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { AISignalOutput } from '@/ai/flows/ai-signal-generation';
import { cn } from '@/lib/utils';

interface SignalCardProps {
  symbol: string;
  type: 'Forex' | 'Crypto';
  signal: AISignalOutput;
  isLocked?: boolean;
}

export const SignalCard = ({ symbol, type, signal, isLocked }: SignalCardProps) => {
  const isBuy = signal.direction === 'Buy';
  const containerRef = useRef<HTMLDivElement>(null);
  
  const sentiment = useMemo(() => {
    const base = isBuy ? 68 : 32;
    const random = Math.floor(Math.random() * 10);
    return isBuy ? base + random : base - random;
  }, [isBuy, symbol]);

  useEffect(() => {
    if (!containerRef.current || isLocked) return;
    
    const widgetContainer = containerRef.current.querySelector('.tradingview-widget-container__widget');
    if (widgetContainer) widgetContainer.innerHTML = '';

    const script = document.createElement("script");
    script.src = "https://s3.tradingview.com/external-embedding/embed-widget-technical-analysis.js";
    script.type = "text/javascript";
    script.async = true;
    script.innerHTML = JSON.stringify({
      "interval": "1h",
      "width": "100%",
      "isTransparent": true,
      "height": "100%",
      "symbol": type === 'Forex' ? `FX:${symbol.replace('/', '')}` : `BINANCE:${symbol}USDT`,
      "showIntervalTabs": false,
      "displayMode": "single",
      "locale": "en",
      "colorTheme": "dark"
    });
    
    containerRef.current.appendChild(script);
  }, [symbol, type, isLocked]);
  
  return (
    <Card className={cn(
      "relative overflow-hidden border-white/5 bg-[#121212]/40 glassmorphism transition-all duration-500 hover:border-primary/50 group rounded-3xl",
      isLocked && "cursor-not-allowed",
      !isLocked && (isBuy ? "hover:glow-emerald" : "hover:glow-crimson")
    )}>
      <div className={`absolute top-0 left-0 w-1 h-full ${isBuy ? 'bg-accent' : 'bg-destructive'}`} />
      
      <CardHeader className="flex flex-row items-center justify-between pb-2 px-6 pt-6">
        <div className="space-y-1">
          <CardTitle className="text-2xl font-black font-headline flex items-center gap-3 tracking-tighter">
            {symbol}
            <Badge variant="secondary" className="text-[9px] uppercase font-black tracking-widest bg-white/5 border-white/10">
              {type}
            </Badge>
          </CardTitle>
          <p className="text-[10px] text-muted-foreground/60 uppercase tracking-[0.3em] font-black">
            PRO AI EXECUTION
          </p>
        </div>
        <div className={cn(
          "flex items-center gap-2 font-black text-2xl tracking-tighter",
          isBuy ? 'text-accent neon-text-emerald' : 'text-destructive neon-text-crimson',
          isLocked && "blur-sm"
        )}>
          {isBuy ? <TrendingUp className="h-6 w-6" /> : <TrendingDown className="h-6 w-6" />}
          {isLocked ? 'LOCKED' : signal.direction.toUpperCase()}
        </div>
      </CardHeader>

      <CardContent className="space-y-6 p-6 pt-4">
        {isLocked ? (
          <div className="absolute inset-0 z-20 bg-black/90 backdrop-blur-2xl flex flex-col items-center justify-center p-8 text-center">
            <div className="h-16 w-16 rounded-2xl bg-primary/10 border border-primary/30 flex items-center justify-center mb-6 shadow-[0_0_30px_rgba(59,130,246,0.2)]">
              <Lock className="h-8 w-8 text-primary animate-pulse" />
            </div>
            <h4 className="text-xl font-black font-headline text-white mb-2 tracking-tighter uppercase">VIP ACCESS REQUIRED</h4>
            <p className="text-xs text-muted-foreground/60 max-w-[220px] font-bold">Unlock institutional price targets and real-time technical gauges.</p>
          </div>
        ) : null}

        <div className={cn("grid grid-cols-3 gap-6 p-5 rounded-2xl bg-black/40 border border-white/5", isLocked && "blur-md")}>
          <div className="space-y-1">
            <p className="text-[9px] text-muted-foreground/60 uppercase font-black tracking-widest">Entry</p>
            <p className="text-sm font-mono font-bold text-white">{signal.entryPrice.toLocaleString()}</p>
          </div>
          <div className="space-y-1 border-x border-white/5 px-6">
            <p className="text-[9px] text-accent uppercase font-black tracking-widest">Take Profit</p>
            <p className="text-sm font-mono font-bold text-accent">{signal.takeProfit.toLocaleString()}</p>
          </div>
          <div className="space-y-1">
            <p className="text-[9px] text-destructive uppercase font-black tracking-widest">Stop Loss</p>
            <p className="text-sm font-mono font-bold text-destructive">{signal.stopLoss.toLocaleString()}</p>
          </div>
        </div>

        {/* Sentiment Section */}
        <div className={cn("space-y-3", isLocked && "blur-md")}>
          <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-[0.2em]">
            <span className="flex items-center gap-1.5 text-accent"><Users className="h-3 w-3" /> Bulls {sentiment}%</span>
            <span className="text-destructive">Bears {100 - sentiment}%</span>
          </div>
          <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden flex">
            <div className="h-full bg-accent transition-all duration-1000 glow-emerald" style={{ width: `${sentiment}%` }} />
            <div className="h-full bg-destructive transition-all duration-1000 glow-crimson" style={{ width: `${100 - sentiment}%` }} />
          </div>
        </div>

        {/* Technical Analysis Gauge */}
        <div className={cn("h-48 border border-white/5 rounded-2xl bg-black/60 p-1 relative overflow-hidden", isLocked && "blur-md")}>
           <div className="absolute top-3 left-4 text-[8px] font-black text-muted-foreground/40 uppercase tracking-[0.4em] z-10">Real-time Gauges</div>
          <div ref={containerRef} className="tradingview-widget-container h-full">
            <div className="tradingview-widget-container__widget"></div>
          </div>
        </div>

        <div className={cn("space-y-3", isLocked && "blur-md")}>
          <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
            <span className="text-muted-foreground">Confidence Metric</span>
            <span className="text-primary">{signal.confidenceScore}%</span>
          </div>
          <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
            <div 
              className="h-full bg-primary transition-all duration-1000 glow-primary"
              style={{ width: `${signal.confidenceScore}%` }}
            />
          </div>
        </div>

        <div className={cn("pt-2", isLocked && "blur-md")}>
          <div className="rounded-xl bg-white/5 border border-white/5 p-4 text-[11px] text-muted-foreground font-medium italic leading-relaxed">
            <Info className="h-3 w-3 inline mr-2 text-primary opacity-60" />
            {signal.reasoning}
          </div>
        </div>
      </CardContent>
    </Card>
  );
};